import{_ as e,o as i,c as l,ai as t}from"./chunks/framework.ampVZV4B.js";const g=JSON.parse('{"title":"05 多步任务与可靠性：重试、超时、日志、幂等","description":"","frontmatter":{},"headers":[],"relativePath":"ai/stage-2-agent/05-reliability.md","filePath":"ai/stage-2-agent/05-reliability.md"}'),r={name:"ai/stage-2-agent/05-reliability.md"};function n(o,a,s,_,c,d){return i(),l("div",null,[...a[0]||(a[0]=[t('<h1 id="_05-多步任务与可靠性-重试、超时、日志、幂等" tabindex="-1">05 多步任务与可靠性：重试、超时、日志、幂等 <a class="header-anchor" href="#_05-多步任务与可靠性-重试、超时、日志、幂等" aria-label="Permalink to “05 多步任务与可靠性：重试、超时、日志、幂等”">​</a></h1><blockquote><p>目标：让你的 Agent 从“能跑”变成“更稳定、可复用”，避免一报错就中断或写坏文件。</p></blockquote><h2 id="_1-你一定会遇到的问题" tabindex="-1">1）你一定会遇到的问题 <a class="header-anchor" href="#_1-你一定会遇到的问题" aria-label="Permalink to “1）你一定会遇到的问题”">​</a></h2><ul><li>模型超时/限流</li><li>输出格式漂移（不按模板）</li><li>多次运行生成重复文件</li><li>写入中途失败导致半成品</li></ul><h2 id="_2-最低成本的工程化加固" tabindex="-1">2）最低成本的工程化加固 <a class="header-anchor" href="#_2-最低成本的工程化加固" aria-label="Permalink to “2）最低成本的工程化加固”">​</a></h2><ul><li><strong>超时 + 重试</strong>：对 LLM 调用做超时，失败重试 1～3 次</li><li><strong>输出校验</strong>：检查是否包含必须栏目（题目/答案/追问/易错点）</li><li><strong>幂等</strong>：同一输入生成同一路径时，不覆盖，改成追加时间戳</li><li><strong>日志</strong>：记录一次任务的输入、输出路径、字数、耗时、错误</li></ul><h2 id="_3-今日练习-40-分钟" tabindex="-1">3）今日练习（40 分钟） <a class="header-anchor" href="#_3-今日练习-40-分钟" aria-label="Permalink to “3）今日练习（40 分钟）”">​</a></h2><ul><li>给你的 Agent 加上输出校验：不合格就自动让模型“按模板重写”</li></ul>',8)])])}const b=e(r,[["render",n]]);export{g as __pageData,b as default};
